<script setup lang="ts">import{ref}from'vue';import{useGrantStore}from'../store';const store=useGrantStore(),title=ref(''),programme=ref('Digital Europe'),partners=ref(3),message=ref('');const submit=()=>{if(title.value.trim().length<4||partners.value<1){message.value='Add a bid name and at least one partner.';return}store.createBid(title.value,programme.value,partners.value);title.value='';message.value='Bid workspace created.'}</script><template><main class="page"><span class="eyebrow">Controlled delivery</span><h1>Bid workspace</h1><p>Move from opportunity to evidence-backed submission with clear ownership.</p><div class="studio"><form @submit.prevent="submit"><h2>Create a bid</h2><label>Bid name<input v-model="title"/></label><label>Programme<select v-model="programme"><option>Digital Europe</option><option>Horizon Europe</option><option>Creative Europe</option><option>CEF Transport</option></select></label><label>Consortium partners<input v-model.number="partners" type="number" min="1" max="30"/></label><button>Create workspace</button><p role="status">{{message}}</p></form><section><h2>Active submissions</h2><div v-for="item in store.cohorts" :key="item.title" class="slate"><div><b>{{item.title}}</b><small>{{item.team}} · {{item.seats}} partners</small></div><span>{{item.status}}</span></div></section></div></main></template>
